function withLogging(f) {
  return function (...args) {
    try {
      return f(...args);
    } catch (e) {
      console.log('Error:', e.message);
    }
  };
}

const risky = withLogging(function (x) {
  if (x < 0) throw new Error('negative!');
  return x * 2;
});

console.log(risky(5));
console.log(risky(-1));

